"use strict";parserFactory.register("noveltranslatedbyc.blogspot.com",()=>new NoveltranslatedbycParser);class NoveltranslatedbycParser extends BlogspotParser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("article button")].map(NoveltranslatedbycParser.buttonToChapter)}static buttonToChapter(e){let t=e.getAttribute("onclick")||"",r=t.indexOf("https"),n=t.lastIndexOf("'"),l="";if(-1!==r&&-1!==n)l=t.substring(r,n);else{let t=e.querySelector("a")||e.closest("a");l=t?t.getAttribute("href")||t.href:""}return{title:e.textContent.trim(),sourceUrl:l}}findContent(e){return e.querySelector("article center")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"button"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,"article")}}